from collections import deque
import sys
input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    grid = []
    lab = None
    for i in range(n):
        row = input().strip()
        grid.append(list(row))
        for j in range(len(row)):
            if row[j] == 'L':
                lab = (i, j)

    dirs = [(-1,0),(1,0),(0,-1),(0,1)]

    # For each free cell, count free neighbors
    bad_count = [[0]*m for _ in range(n)]
    for i in range(n):
        for j in range(m):
            if grid[i][j] != '#':
                cnt = 0
                for di, dj in dirs:
                    ni, nj = i+di, j+dj
                    if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#':
                        cnt += 1
                bad_count[i][j] = cnt

    good = [[False]*m for _ in range(n)]
    q = deque()
    li, lj = lab
    good[li][lj] = True
    q.append((li, lj))

    while q:
        i, j = q.popleft()
        for di, dj in dirs:
            ni, nj = i+di, j+dj
            if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#' and not good[ni][nj]:
                bad_count[ni][nj] -= 1
                if bad_count[ni][nj] <= 1:
                    good[ni][nj] = True
                    q.append((ni, nj))

    out = []
    for i in range(n):
        row = grid[i]
        for j in range(m):
            if row[j] == '.' and good[i][j]:
                row[j] = '+'
        out.append(''.join(row))
    print('\n'.join(out))

